from dataclasses import dataclass
from typing import List

@dataclass
class TextType:
    label: str = 'text'
    required: bool = False

def build_form(builder: List[TextType], options: dict) -> None:
    builder.append(TextType())

def configure_options(resolver: dict) -> None:
    resolver['data_class'] = TextType

def get_block_prefix() -> str:
    return 'symfony_form_text'
